import json
from dataclasses import dataclass, field

@dataclass
class StepResult:
    step_id: str
    tool: str
    args: dict
    result: str           # JSON string returned by the tool
    success: bool
    error: str | None = None

class SequentialExecutor:
    """
    Executes plan steps one at a time in dependency order.
    Records results and makes them available to subsequent steps.
    """
    def __init__(self, dispatch: dict):
        self.dispatch = dispatch
        self._results: dict[str, StepResult] = {}  # step_id -> StepResult

    def get_result(self, step_id: str) -> str | None:
        """Return the result string for a completed step."""
        r = self._results.get(step_id)
        return r.result if r and r.success else None

    def _execution_order(self, steps: list[dict]) -> list[dict]:
        """Topological sort — return steps in a valid execution order."""
        completed: set[str] = set()
        ordered = []
        remaining = list(steps)
        while remaining:
            # Find all steps whose dependencies are satisfied
            ready = [s for s in remaining if all(d in completed for d in s.get("depends_on", []))]
            if not ready:
                raise ValueError(f"Unresolvable dependencies in remaining steps: {[s['step_id'] for s in remaining]}")
            # Execute in deterministic order (by step_id)
            ready.sort(key=lambda s: s["step_id"])
            for step in ready:
                ordered.append(step)
                completed.add(step["step_id"])
            remaining = [s for s in remaining if s["step_id"] not in completed]
        return ordered

    def execute(self, plan: dict) -> dict:
        """
        Execute all steps in the plan. Returns a summary with all results.
        """
        steps = plan.get("steps", [])
        ordered = self._execution_order(steps)
        failed_steps = []

        for step in ordered:
            step_id = step["step_id"]
            tool = step["tool"]
            args = step.get("args", {})

            fn = self.dispatch.get(tool)
            if fn is None:
                result = StepResult(step_id, tool, args, "", False,
                                    f"Tool '{tool}' not found in dispatch")
                self._results[step_id] = result
                failed_steps.append(step_id)
                continue

            try:
                result_str = fn(**args)
                self._results[step_id] = StepResult(step_id, tool, args, result_str, True)
            except Exception as e:
                result_str = json.dumps({"error": str(e)})
                self._results[step_id] = StepResult(step_id, tool, args, result_str, False, str(e))
                failed_steps.append(step_id)

        return {
            "status": "complete" if not failed_steps else "partial",
            "failed_steps": failed_steps,
            "results": {sid: r.result for sid, r in self._results.items()},
        }

