from concurrent.futures import ThreadPoolExecutor, as_completed

class ParallelExecutor:
    """
    Executes independent steps in parallel using thread pools.
    Steps within the same execution wave run concurrently.
    """
    def __init__(self, dispatch: dict, max_workers: int = 4):
        self.dispatch = dispatch
        self.max_workers = max_workers
        self._results: dict[str, StepResult] = {}

    def _execution_waves(self, steps: list[dict]) -> list[list[dict]]:
        """Group steps into waves using topological ordering."""
        completed: set[str] = set()
        remaining = list(steps)
        waves = []
        while remaining:
            wave = [s for s in remaining if all(d in completed for d in s.get("depends_on", []))]
            if not wave:
                break
            waves.append(wave)
            for s in wave:
                completed.add(s["step_id"])
            remaining = [s for s in remaining if s["step_id"] not in completed]
        return waves

    def _execute_step(self, step: dict) -> StepResult:
        step_id = step["step_id"]
        tool = step["tool"]
        args = step.get("args", {})
        fn = self.dispatch.get(tool)
        if fn is None:
            return StepResult(step_id, tool, args, "", False, f"Unknown tool: {tool}")
        try:
            result_str = fn(**args)
            return StepResult(step_id, tool, args, result_str, True)
        except Exception as e:
            return StepResult(step_id, tool, args, json.dumps({"error": str(e)}), False, str(e))

    def execute(self, plan: dict) -> dict:
        steps = plan.get("steps", [])
        waves = self._execution_waves(steps)
        failed_steps = []

        for wave_num, wave in enumerate(waves):
            with ThreadPoolExecutor(max_workers=min(len(wave), self.max_workers)) as pool:
                futures = {pool.submit(self._execute_step, step): step["step_id"]
                           for step in wave}
                for future in as_completed(futures):
                    step_id = futures[future]
                    result = future.result()
                    self._results[step_id] = result
                    if not result.success:
                        failed_steps.append(step_id)

        return {
            "status": "complete" if not failed_steps else "partial",
            "failed_steps": failed_steps,
            "waves_executed": len(waves),
            "results": {sid: r.result for sid, r in self._results.items()},
        }

