def execute_with_skip_strategy(plan: dict, dispatch: dict) -> dict:
    """
    Execute plan steps, skipping any step whose dependency failed.
    Steps that are not affected by failures still run.
    """
    steps_by_id = {s["step_id"]: s for s in plan.get("steps", [])}
    results: dict[str, StepResult] = {}
    failed: set[str] = set()
    skipped: set[str] = set()

    # Topological order
    ordered = []
    completed: set[str] = set()
    remaining = list(plan.get("steps", []))
    while remaining:
        ready = [s for s in remaining
                 if all(d in completed or d in failed or d in skipped
                        for d in s.get("depends_on", []))]
        if not ready:
            break
        for s in sorted(ready, key=lambda x: x["step_id"]):
            ordered.append(s)
            completed.add(s["step_id"])
        remaining = [s for s in remaining if s["step_id"] not in completed]

    for step in ordered:
        sid = step["step_id"]
        # Check if any dependency failed or was skipped
        deps_failed = any(d in failed or d in skipped for d in step.get("depends_on", []))
        if deps_failed:
            skipped.add(sid)
            continue

        fn = dispatch.get(step["tool"])
        try:
            result_str = fn(**step["args"]) if fn else json.dumps({"error": "Unknown tool"})
            ok = '"error"' not in result_str and '"ok": false' not in result_str
            results[sid] = StepResult(sid, step["tool"], step["args"], result_str, ok)
            if not ok:
                failed.add(sid)
        except Exception as e:
            results[sid] = StepResult(sid, step["tool"], step["args"], "", False, str(e))
            failed.add(sid)

    return {
        "status": "complete" if not failed else "partial",
        "failed": list(failed),
        "skipped": list(skipped),
        "results": {sid: r.result for sid, r in results.items()},
    }
